在 Python 中，流程控制语句用于控制程序的执行流程。常见的流程控制语句包括条件语句（如 if 语句）和循环语句（如 for 和 while 语句）。本文将介绍这些基本的流程控制语句，并提供一些示例代码。
1 条件判断#if (2 &lt;= 3) and (7 != 8): print((2 &lt;= 3) and (7 != 8)) # True if not (1 == 1): print(not (1 == 1)) else: print(not (1 == 1)) # False score = int(input(&#34;Enter score:\n&#34;)) if score &gt; 100 or score &lt; 0: print(&#39;Invalid score. Please enter a score between 0 and 100.&#39;) elif score &gt;= 90: print(&#39;Grade: A&#39;) elif score &gt;= 80: print(&#39;Grade: B&#39;) elif score &gt;= 70: print(&#39;Grade: C&#39;) elif score &gt;= 60: print(&#39;Grade: D&#39;) else: print(&#39;Grade: F&#39;)2 随机数#import random RR = random.randint(1, 100) II = input(&#39;Please enter a number between 0 and 100.\n&#39;) II = int(II) if II &lt; RR: print(&#39;Too low!&#39;) elif II &gt; RR: print(&#39;Too high!&#39;) else: print(&#39;Correct!&#39;)3 while 循环#i = 1 while i &lt;= 5: j = 1 while j &lt;= i: # 嵌套 print(&#34;*&#34;, end=&#34; &#34;) # 指定打印结束后添加的内容 j += 1 print() # 缩进换行 i += 14 for 循环#name = &#34;Hello&#34; for i in name: print(i, end=&#34; &#34;) # H e l l o print() for i in range(1, 6): for j in range(1, i + 1): print(&#34;*&#34;, end=&#34; &#34;) print()5 break 和 continue#在嵌套循环中，break continue 只对当前循环有效，不会影响外层循环。
for i in range(1, 11): if i == 5: break print(i, end=&#34; &#34;) print() for i in range(1, 11): if i == 5: continue print(i, end=&#34; &#34;) print()

for_each() 是一个遍历算法，它对指定范围内的每个元素执行给定的可调用对象（仿函数、Lambda 表达式、函数指针），并返回该可调用对象，以便获取其最终状态。
#include &lt;algorithm&gt; for_each(InputIterator first, InputIterator last, Function fn);1 普通函数#向 std::for_each 传入普通函数时，函数名会自动转换为指向该函数的指针。
#include &lt;iostream&gt; #include &lt;vector&gt; #include &lt;algorithm&gt; void print(int n) { std::cout &lt;&lt; n &lt;&lt; &#34; &#34;; } void doubleValue(int &amp;n) { n *= 2; } int main() { std::vector&lt;int&gt; vec = {1, 2, 3, 4, 5}; std::for_each(vec.begin(), vec.end(), doubleValue); std::for_each(vec.begin(), vec.end(), print); return 0; }2 仿函数#仿函数（函数对象） 是重载了函数调用操作符 () 的类对象，它们可以像普通函数一样被调用，但对象内部存储的数据成员使其具有状态。
#include &lt;iostream&gt; #include &lt;vector&gt; #include &lt;algorithm&gt; class Sum { private: int total = 0; public: void operator()(int n) { total += n; } int getTotal() const { return total; } }; int main() { std::vector&lt;int&gt; vec = {1, 2, 3, 4, 5}; Sum sum = std::for_each(vec.begin(), vec.end(), Sum()); std::cout &lt;&lt; sum.getTotal() &lt;&lt; std::endl; return 0; }以上 Sum() 是临时对象，for_each() 返回的是修改后的函数对象
// 错误写法 Sum s; std::for_each(vec.begin(), vec.end(), s); // 传入的是 s 的拷贝 // s.total 还是 0，因为修改的是拷贝 // 正确写法 Sum s; std::for_each(vec.begin(), vec.end(), std::ref(s)); // 传引用 3 Lambda 表达式#Lambda 表达式是 C++11 引入的一种创建匿名函数对象的简洁语法，它允许在函数内部直接定义可调用代码块，并能通过捕获列表访问其作用域内的变量。
[captures] (params) lambda-specifiers -&gt; return type { body }captures 捕获列表，可以把上下文变量以值或引用的方式捕获，在 body 中使用
params 形参列表，可以省略，表示无参函数
lambda-specifiers 说明符，可选项有 mutable exception 等
return type 返回值类型，可以省略，由编译器自动推导
body 函数体，函数实现，可以为空，但是不能省略 {}
#include &lt;iostream&gt; #include &lt;vector&gt; #include &lt;algorithm&gt; int main() { std::vector&lt;int&gt; vec = {1, 2, 3, 4, 5}; // 1. 统计偶数个数（按引用捕获外部作用域中所有变量） int evenCount = 0; std::for_each(vec.begin(), vec.end(), [&amp;](int n) { if (n % 2 == 0) evenCount++; } ); std::cout &lt;&lt; &#34;evenCount: &#34; &lt;&lt; evenCount &lt;&lt; std::endl; // 2. 修改容器元素（用引用） std::for_each(vec.begin(), vec.end(), [](int &amp;n) { n *= 5; } ); // 3. 打印每个元素 std::for_each(vec.begin(), vec.end(), [](int n) { std::cout &lt;&lt; n &lt;&lt; &#34; &#34;; } ); std::cout &lt;&lt; std::endl; return 0; }4 函数指针#函数指针是指向函数的指针变量，它可以存储函数的地址，并通过该指针调用函数。
// 返回值类型 (*函数指针名)(参数列表) #include &lt;iostream&gt; #include &lt;vector&gt; #include &lt;algorithm&gt; int print(int&amp; n) { std::cout &lt;&lt; n &lt;&lt; &#34; &#34;; return 0; } int square(int&amp; n) { return n *= n; } class Line { private: int cnt = 0; public: void operator()() { cnt++; std::cout &lt;&lt; std::endl &lt;&lt; std::endl; std::cout &lt;&lt; &#34;------ &#34; &lt;&lt; cnt &lt;&lt; &#34; ------&#34; &lt;&lt; std::endl; } }; int main() { Line line; std::vector&lt;int&gt; vec = {1, 2, 3, 4, 5}; // 1. 直接使用函数名（函数名自动转换为指针） line(); std::for_each(vec.begin(), vec.end(), print); // 2. 声明函数指针变量（指向接受一个 int&amp;、返回 int 的函数） line(); int (*printPtr)(int&amp;) = print; std::for_each(vec.begin(), vec.end(), printPtr); // 3. 定义一个函数，接受函数指针作为参数 line(); auto processVector = [](std::vector&lt;int&gt;&amp; v, int (*func)(int&amp;)) { std::for_each(v.begin(), v.end(), func); }; processVector(vec, square); processVector(vec, printPtr); // 4. 函数指针数组 line(); int (*operations[])(int&amp;) = {square, print}; for (auto op : operations) { std::for_each(vec.begin(), vec.end(), op); } // 5. 函数指针与 transform 结合 line(); int (*squarePtr)(int&amp;) = square; std::vector&lt;int&gt; result(vec.size()); std::transform(vec.begin(), vec.end(), result.begin(), squarePtr); std::for_each(result.begin(), result.end(), print); // 6. 使用 typedef 简化 line(); typedef int (*PrintFunc)(int&amp;); PrintFunc pf = print; std::for_each(vec.begin(), vec.end(), pf); // 7. 使用 using 简化 line(); using UnaryOp = int(*)(int&amp;); UnaryOp uop = print; std::for_each(vec.begin(), vec.end(), uop); return 0; }

1 预定义标准流对象#在 C++ 中，预定义标准流对象是 iostream 库提供的几个全局对象，表示标准的输入输出设备（通常是键盘和屏幕）。这些对象在程序启动时自动创建，可以直接使用。
对象 名称 对应设备 相当于C语言 类 cin 标准输入 键盘 stdin istream cout 标准输出 屏幕 stdout ostream cerr 标准错误 屏幕 stderr 无缓冲 ostream clog 标准日志 屏幕 stderr 有缓冲 ostream 2 文件 I/O 实现#文件 I/O 定义于头文件 &lt;fstream&gt;
文件的打开 open() 与关闭 close() 是文件操作的标准流程； 成员函数 open() 的第二个参数规定了文件的打开模式，可选项有追加模式 ios::app 等； 指针定位 seekg() seekp() 是对文件内部进行随机访问的关键； &lt;&lt; 流插入运算符和左移运算符重载，&gt;&gt; 流提取运算符和右移运算符重载； C++ 的流机制支持文件、字符串、数组等多种介质，I/O 具有多样性。 类 名称 描述 ifstream 输入文件流 用于从文件读取信息 ofstream 输出文件流 用于创建文件并向文件写入信息 fstream 文件流 能同时读写文件 #include &lt;fstream&gt; // 文件流操作 #include &lt;iostream&gt; // 标准输入输出 using namespace std; int main() { char data[100]; // 1. 写入文件 ofstream outfile; // 创建输出文件流对象 outfile.open(&#34;afile.dat&#34;); // 打开文件，写入模式 ios::out if (!outfile.is_open()) { // 检查流对象是否关联了文件 cerr &lt;&lt; &#34;The file &#39;afile.dat&#39; does not exist&#34; &lt;&lt; endl; return 1; } cout &lt;&lt; &#34;Writing to the file&#34; &lt;&lt; endl; cout &lt;&lt; &#34;Enter your name: &#34;; cin.getline(data, 100); // 从键盘读取一行，最多 100 个字符 outfile &lt;&lt; data &lt;&lt; endl; // 将姓名写入文件，并添加换行 cout &lt;&lt; &#34;Enter your age: &#34;; cin &gt;&gt; data; cin.ignore(); // 清空输入缓冲区，消除上一次输入对下一次输入的影响 outfile &lt;&lt; data &lt;&lt; endl; // 将年龄写入文件 outfile.close(); // 关闭文件，确保数据写入磁盘 // 2. 读取文件 ifstream infile(&#34;afile.dat&#34;); // 以读取模式打开文件 if (!infile.is_open()) { cerr &lt;&lt; &#34;The file &#39;afile.dat&#39; does not exist&#34; &lt;&lt; endl; return 1; } cout &lt;&lt; &#34;Reading from the file&#34; &lt;&lt; endl; while (infile &gt;&gt; data) { cout &lt;&lt; data &lt;&lt; endl; } infile.close(); return 0; }
